import{_ as t,o as r,c as n,a2 as i}from"./chunks/framework._toPeeIm.js";const b=JSON.parse('{"title":"Checkliste zur Vermeidung von Anti-Patterns","description":"Checkliste zur Vermeidung von Antipatterns beim Schreiben von RxJS-Code. 16 Best Practices für korrekte Subscription-Kündigung, Subject-Nutzung, Fehlerbehandlung und Memory-Leak-Prävention.","frontmatter":{"description":"Checkliste zur Vermeidung von Antipatterns beim Schreiben von RxJS-Code. 16 Best Practices für korrekte Subscription-Kündigung, Subject-Nutzung, Fehlerbehandlung und Memory-Leak-Prävention."},"headers":[],"relativePath":"de/guide/anti-patterns/checklist.md","filePath":"de/guide/anti-patterns/checklist.md","lastUpdated":1765295683000}'),a={name:"de/guide/anti-patterns/checklist.md"};function s(d,e,o,c,l,h){return r(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="checkliste-zur-vermeidung-von-anti-patterns" tabindex="-1">Checkliste zur Vermeidung von Anti-Patterns <a class="header-anchor" href="#checkliste-zur-vermeidung-von-anti-patterns" aria-label="Permalink to &quot;Checkliste zur Vermeidung von Anti-Patterns&quot;">​</a></h1><p>Verwenden Sie diese Checkliste, um Ihren RxJS-Code auf Anti-Patterns zu überprüfen. Klicken Sie auf jeden Punkt, um eine detaillierte Erklärung und Beispielcode zu erhalten.</p><h2 id="checkliste" tabindex="-1">Checkliste <a class="header-anchor" href="#checkliste" aria-label="Permalink to &quot;Checkliste&quot;">​</a></h2><h3 id="🔴-kritische-probleme-vermeiden" tabindex="-1">🔴 Kritische Probleme vermeiden <a class="header-anchor" href="#🔴-kritische-probleme-vermeiden" aria-label="Permalink to &quot;🔴 Kritische Probleme vermeiden&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Check</th><th>Punkt</th><th>Hinweis</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#1-subject-外部公開">Subject über asObservable() veröffentlichen</a></strong></td><td><code>Subject</code> nicht direkt exportieren, sondern als Observable über <code>asObservable()</code> bereitstellen<br>Zustandsänderungen nur über dedizierte Methoden ermöglichen</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#2-ネストした-subscribe-コールバック地獄">Verschachtelte subscribe vermeiden</a></strong></td><td>Kein weiteres <code>subscribe</code> innerhalb eines <code>subscribe</code> aufrufen<br>Mit <code>switchMap</code>, <code>mergeMap</code>, <code>concatMap</code> etc. flach machen</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#3-unsubscribe-忘れ-メモリリーク">Unendliche Streams immer abbestellen</a></strong></td><td>Unendliche Streams wie Event-Listener immer abbestellen<br><code>takeUntil</code>-Muster oder <code>Subscription</code>-Verwaltung</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#4-sharereplay-の誤用">shareReplay-Einstellungen explizit angeben</a></strong></td><td>Format <code>shareReplay({ bufferSize: 1, refCount: true })</code> verwenden<br>Referenzzählung aktivieren um Memory-Leaks zu verhindern</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./subscribe-if-hell">Verschachtelte if-Anweisungen in subscribe vermeiden</a></strong></td><td>Komplexe Verzweigungen (3+ Verschachtelungen) in <code>subscribe</code> vermeiden<br>Deklarativ mit <code>filter</code>, <code>iif</code>, <code>partition</code> etc. schreiben</td></tr></tbody></table><h3 id="🟡-probleme-die-aufmerksamkeit-erfordern" tabindex="-1">🟡 Probleme die Aufmerksamkeit erfordern <a class="header-anchor" href="#🟡-probleme-die-aufmerksamkeit-erfordern" aria-label="Permalink to &quot;🟡 Probleme die Aufmerksamkeit erfordern&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Check</th><th>Punkt</th><th>Hinweis</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#5-map-での副作用">map ist reine Funktion, Seiteneffekte in tap</a></strong></td><td>In <code>map</code> keine Zustandsänderungen oder Log-Ausgaben<br>Seiteneffekte explizit mit <code>tap</code>-Operator trennen</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#6-cold-hot-observable-の違いの無視">Cold/Hot richtig unterscheiden</a></strong></td><td>HTTP-Requests etc. mit <code>shareReplay</code> in Hot umwandeln<br>Entscheiden ob pro Subscription oder geteilt ausführen</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#7-promise-と-observable-の不適切な混在">Promise mit from konvertieren</a></strong></td><td>Promise und Observable nicht mischen<br>Mit <code>from()</code> in Observable konvertieren und einheitlich verarbeiten</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#8-バックプレッシャーの無視">Hochfrequente Events kontrollieren</a></strong></td><td>Sucheingabe mit <code>debounceTime</code>, Scrollen mit <code>throttleTime</code> kontrollieren<br>Duplikate mit <code>distinctUntilChanged</code> ausschließen</td></tr></tbody></table><h3 id="🔵-verbesserung-der-codequalitat" tabindex="-1">🔵 Verbesserung der Codequalität <a class="header-anchor" href="#🔵-verbesserung-der-codequalitat" aria-label="Permalink to &quot;🔵 Verbesserung der Codequalität&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Check</th><th>Punkt</th><th>Hinweis</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#9-エラーの握りつぶし">Fehler richtig behandeln</a></strong></td><td>Fehler mit <code>catchError</code> abfangen und richtig verarbeiten<br>Benutzerfreundliche Fehlermeldungen anzeigen<br>Bei Bedarf mit <code>retry</code> / <code>retryWhen</code> wiederholen</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#10-dom-イベントサブスクリプションのリーク">DOM-Events richtig freigeben</a></strong></td><td><code>fromEvent</code>-Subscriptions immer beenden<br>Bei Komponenten-Zerstörung automatisch mit <code>takeUntil</code> abbestellen</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#11-型安全性の欠如-any-の多用">Typsicherheit gewährleisten</a></strong></td><td>Interfaces und Type-Aliase definieren<br>Typparameter für <code>Observable&lt;T&gt;</code> explizit angeben<br>TypeScript-Typinferenz nutzen</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#12-不適切なオペレーター選択">Passende Operatoren wählen</a></strong></td><td>Suche: <code>switchMap</code>, parallel: <code>mergeMap</code><br>Sequentiell: <code>concatMap</code>, Doppelklick-Schutz: <code>exhaustMap</code></td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#13-過度な複雑化">Einfache Verarbeitung braucht kein RxJS</a></strong></td><td>Array-Verarbeitung etc. reicht normales JavaScript<br>RxJS für asynchrone Verarbeitung und Event-Streams verwenden</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#14-subscribe-内での状態変更">Zustand reaktiv verwalten</a></strong></td><td>Zustand mit <code>BehaviorSubject</code> oder <code>scan</code> verwalten<br><code>subscribe</code> als finalen Trigger verwenden</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#15-テストの欠如">Tests schreiben</a></strong></td><td>Marble-Tests mit <code>TestScheduler</code> durchführen<br>Asynchrone Verarbeitung synchron testbar machen</td></tr></tbody></table><h2 id="verwendung" tabindex="-1">Verwendung <a class="header-anchor" href="#verwendung" aria-label="Permalink to &quot;Verwendung&quot;">​</a></h2><h3 id="_1-bei-code-reviews" tabindex="-1">1. Bei Code-Reviews <a class="header-anchor" href="#_1-bei-code-reviews" aria-label="Permalink to &quot;1. Bei Code-Reviews&quot;">​</a></h3><p>Nach dem Schreiben von neuem Code diese Checkliste für Selbst-Reviews nutzen.</p><h3 id="_2-bei-pull-requests" tabindex="-1">2. Bei Pull Requests <a class="header-anchor" href="#_2-bei-pull-requests" aria-label="Permalink to &quot;2. Bei Pull Requests&quot;">​</a></h3><p>Diese Checkliste in Pull-Request-Vorlagen einbinden für gemeinsame Überprüfungskriterien.</p><h3 id="_3-regelmaßige-uberprufung" tabindex="-1">3. Regelmäßige Überprüfung <a class="header-anchor" href="#_3-regelmaßige-uberprufung" aria-label="Permalink to &quot;3. Regelmäßige Überprüfung&quot;">​</a></h3><p>Diese Checkliste regelmäßig auf bestehende Codebasen anwenden um Anti-Pattern-Einschleichung zu erkennen.</p><h3 id="_4-team-sharing" tabindex="-1">4. Team-Sharing <a class="header-anchor" href="#_4-team-sharing" aria-label="Permalink to &quot;4. Team-Sharing&quot;">​</a></h3><p>Mit Teammitgliedern teilen um RxJS Best Practices zu vereinheitlichen.</p><h2 id="verwandte-ressourcen" tabindex="-1">Verwandte Ressourcen <a class="header-anchor" href="#verwandte-ressourcen" aria-label="Permalink to &quot;Verwandte Ressourcen&quot;">​</a></h2><ul><li><strong><a href="./common-mistakes">Häufige Fehler und Lösungen</a></strong> - Detaillierte Erklärungen und Codebeispiele für jedes Anti-Pattern</li><li><strong><a href="./index">Anti-Pattern-Sammlung Übersicht</a></strong> - Anti-Pattern-Liste und Lernpfad</li><li><strong><a href="/RxJS-with-TypeScript/de/guide/error-handling/strategies">Fehlerbehandlung</a></strong> - Best Practices für Fehlerbehandlung</li><li><strong><a href="/RxJS-with-TypeScript/de/guide/testing/unit-tests">Testmethoden</a></strong> - Wie man RxJS-Code testet</li></ul><h2 id="tipps-zur-checklisten-nutzung" tabindex="-1">Tipps zur Checklisten-Nutzung <a class="header-anchor" href="#tipps-zur-checklisten-nutzung" aria-label="Permalink to &quot;Tipps zur Checklisten-Nutzung&quot;">​</a></h2><ol><li><p><strong>Nicht alle Punkte auf einmal perfekt machen wollen</strong></p><ul><li>Zuerst kritische Probleme (🔴) priorisieren</li><li>Schrittweise verbessern</li></ul></li><li><p><strong>Prioritäten im Team festlegen</strong></p><ul><li>Wichtigkeit je nach Projekteigenschaften anpassen</li><li>Angepasste Checklisten erstellen</li></ul></li><li><p><strong>Automatisierung erwägen</strong></p><ul><li>Automatische Checks mit statischen Analysetools wie ESLint</li><li>In CI/CD-Pipeline integrieren</li></ul></li><li><p><strong>Regelmäßig aktualisieren</strong></p><ul><li>Bei RxJS-Versions-Upgrades aktualisieren</li><li>Team-Erfahrungswissen einarbeiten</li></ul></li></ol><hr><p><strong>Wichtig</strong>: Diese Checkliste dient nicht dem Schreiben von perfektem Code, sondern der Vermeidung häufiger Probleme. Bitte je nach Projektkontext flexibel einsetzen.</p>',24)])])}const m=t(a,[["render",s]]);export{b as __pageData,m as default};
